<script setup lang="ts">import type{Programme}from'../store';import{useGrantStore}from'../store';defineProps<{programme:Programme}>();const store=useGrantStore()</script><template><article class="media-card"><div :class="['art',programme.tone]"><span>{{programme.domain}}</span><button :aria-label="`Shortlist ${programme.title}`" @click="store.toggleSaved(programme.id)">{{store.saved.includes(programme.id)?'✓':'+'}}</button><i :style="{width:`${programme.match}%`}"/></div><h3>{{programme.title}}</h3><p>{{programme.provider}}</p><small>{{programme.level}} · {{programme.duration}} · {{programme.match}}% fit</small></article></template>
